## Source

{{ source }}

## World

- id: {{ world.id }}
- name: {{ world.name }}
- description: {{ world.description }}

## Simulation

- id: {{ simulation.id }}
- current time: {{ simulation.current_time }}

## Current turn

- id: {{ turn.id }}
- sequence: {{ turn.sequence }}
- type: {{ turn.type }}
- content: {{ turn.content }}
- start time: {{ turn.start_time }}

## User input

{{ user_input }}

## Narration

{{ narration }}

## Accepted actions

{% for entry in coordination_result.accepted_actions %}
accepted:{{ loop.index0 }}:
- actor id: {{ entry.actor_id }}
- action index: {{ entry.action_index }}
- summary: {{ entry.summary }}
- action type: {{ entry.action.type }}
- label: {{ entry.action.label }}
- target ids: {{ entry.action.target_ids }}
- utterance: {{ entry.action.utterance }}
- expected effects: {{ entry.action.expected_effects }}
{% else %}
- none
{% endfor %}

## Committed physical changes

{% for operation in state_commit.operations %}
Operation {{ loop.index0 }}:
{{ operation }}
{% else %}
- none
{% endfor %}

## Actors, recent memories, and active intents

{% for entry in actors %}
Actor {{ entry.actor.id }}: {{ entry.actor.name }}
- public state: {{ entry.actor.public_state }}
- private state: {{ entry.actor.private_state }}
- current activity: {{ entry.actor.current_activity.name }}

Recent memories:
{% for memory in entry.recent_memories %}
- memory id: {{ memory.memory.id }}; summary: {{ memory.memory.summary }}; event id: {{ memory.event.id }}; event name: {{ memory.event.name }}; support: {{ memory.support_type }}; confidence: {{ memory.confidence }}; salience: {{ memory.salience }}; stance: {{ memory.stance }}{% if memory.behavioural_relevance %}; behavioural relevance: {{ memory.behavioural_relevance }}{% endif %}
{% else %}
- none
{% endfor %}

Active intents:
{% for intent in entry.intents %}
- intent id: {{ intent.id }}; name: {{ intent.name }}; type: {{ intent.type }}; status: {{ intent.status }}; priority: {{ intent.priority }}; urgency: {{ intent.urgency }}; horizon: {{ intent.horizon }}{% if intent.deadline %}; deadline: {{ intent.deadline }}{% endif %}
  description: {{ intent.description }}
  desired state: {{ intent.desired_state }}
  success conditions: {{ intent.success_conditions }}
  failure conditions: {{ intent.failure_conditions }}
  current plan: {{ intent.current_plan }}
  blockers: {{ intent.blockers }}
  open threads: {{ intent.open_threads }}
{% else %}
- none
{% endfor %}
{% else %}
- none
{% endfor %}
